import json
import pymysql
import os
import re

# Database connection parameters
RDS_HOST = os.environ['RDS_HOST']
RDS_USER = os.environ['RDS_USER']
RDS_PASSWORD = os.environ['RDS_PASSWORD']
RDS_DB_NAME = os.environ['RDS_DB_NAME']

# Establish a connection to the RDS MySQL database
def get_db_connection():
    return pymysql.connect(host=RDS_HOST,
                           user=RDS_USER,
                           password=RDS_PASSWORD,
                           database=RDS_DB_NAME)

# Validate input to prevent SQL injection
def validate_input(input_data):
    if not isinstance(input_data, str):
        return False
    return bool(re.match("^[a-zA-Z0-9_ ]*$", input_data))

# Lambda function handler
def lambda_handler(event, context):
    search_params = event.get('queryStringParameters', {})
    
    # Validate search parameters
    validated_params = {key: value for key, value in search_params.items() if validate_input(value)}
    
    if not validated_params:
        return {
            'statusCode': 400,
            'body': json.dumps({'error': 'Invalid search parameters'})
        }
    
    query = "SELECT * FROM products WHERE "
    conditions = []
    values = []
    
    for key, value in validated_params.items():
        conditions.append(f"{key} = %s")
        values.append(value)
    
    query += " AND ".join(conditions)
    
    try:
        connection = get_db_connection()
        with connection.cursor() as cursor:
            cursor.execute(query, values)
            results = cursor.fetchall()
        
        return {
            'statusCode': 200,
            'body': json.dumps(results)
        }
    
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }
    
    finally:
        connection.close()